// Define a sealed trait for all allowed message types - this acts as an allowlist
sealed trait SecureMessage extends Serializable

final case class TextMessage(sender: String, content: String) extends SecureMessage {
  require(sender != null && sender.length <= 256, "Invalid sender")
  require(content != null && content.length <= 10000, "Invalid content")

  // Sanitize inputs
  val sanitizedSender: String = sender.replaceAll("[^a-zA-Z0-9_\\-.]", "")
  val sanitizedContent: String = content
    .replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F]", "") // Remove control chars
}

final case class PingMessage(timestamp: Long) extends SecureMessage {
  require(timestamp > 0 && timestamp <= System.currentTimeMillis() + 60000, "Invalid timestamp")
}

final case class StatusRequest(requestId: String) extends SecureMessage {
  require(requestId != null && requestId.matches("[a-zA-Z0-9\\-]{1,64}"), "Invalid requestId")
}

final case class StatusResponse(requestId: String, status: String) extends SecureMessage

// Secure JSON serializer/deserializer with type allowlisting
object SecureSerializer {

  private val typeValidator = BasicPolymorphicTypeValidator.builder()
    .allowIfBaseType(classOf[SecureMessage])
    .build()

  private val mapper: ObjectMapper = {
    val m = new ObjectMapper()
    m.registerModule(DefaultScalaModule)
    // Disable dangerous features
    m.disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
    // Activate type validation to prevent polymorphic deserialization attacks
    m.activateDefaultTyping(typeValidator, ObjectMapper.DefaultTyping.NON_FINAL,
      JsonTypeInfo.As.PROPERTY)
    m
  }

  // Allowlist of permitted message classes
  private val allowedClasses: Set[String] = Set(
    classOf[TextMessage].getName,
    classOf[PingMessage].getName,
    classOf[StatusRequest].getName,
    classOf[StatusResponse].getName
  )

  def serialize(msg: SecureMessage): Array[Byte] = {
    mapper.writeValueAsBytes(msg)
  }

  def deserialize(data: Array[Byte], maxSize: Int = 65536): Either[String, SecureMessage] = {
    if (data == null || data.isEmpty) {
      return Left("Empty data")
    }
    if (data.length > maxSize) {
      return Left(s"Data exceeds maximum allowed size of $maxSize bytes")
    }

    try {
      val tree = mapper.readTree(data)

      // Validate the type field against our allowlist before full deserialization
      val typeNode = tree.get("@class")
      if (typeNode == null || typeNode.isNull) {
        return Left("Missing type information")
      }

      val typeName = typeNode.asText()
      if (!allowedClasses.contains(typeName)) {
        return Left(s"Disallowed message type: $typeName")
      }

      val result = mapper.treeToValue(tree, classOf[SecureMessage])
      Right(result)
    } catch {
      case e: IllegalArgumentException =>
        Left(s"Validation failed: ${e.getMessage}")
      case e: Exception =>
        Left(s"Deserialization failed: ${e.getClass.getSimpleName}")
    }
  }
}

// Actor that processes validated messages
class MessageProcessorActor extends Actor with ActorLogging {
  override def receive: Receive = {
    case msg: TextMessage =>
      log.info(s"Received text from ${msg.sanitizedSender}: ${msg.sanitizedContent}")

    case msg: PingMessage =>
      log.info(s"Received ping at ${msg.timestamp}")
      sender() ! StatusResponse("pong", "alive")

    case msg: StatusRequest =>
      log.info(s"Status request: ${msg.requestId}")
      sender() ! StatusResponse(msg.requestId, "ok")

    case unknown =>
      log.warning(s"Received unexpected message type: ${unknown.getClass.getName}")
  }
}

// TCP connection handler that securely deserializes incoming data
class ConnectionHandler(processor: ActorRef) extends Actor with ActorLogging {

  import Tcp._

  private val MaxMessageSize = 65536
  private val RateLimitPerSecond = 100
  private var messageCount = 0L
  private var lastResetTime = System.currentTimeMillis()

  override def receive: Receive = {
    case Received(data) =>
      if (!checkRateLimit()) {
        log.warning("Rate limit exceeded, dropping message")
        sender() ! Close
        return
      }

      handleIncomingData(data)

    case PeerClosed =>
      log.info("Peer closed connection")
      context.stop(self)

    case ErrorClosed(cause) =>
      log.warning(s"Connection error: $cause")
      context.stop(self)
  }

  private def checkRateLimit(): Boolean = {
    val now = System.currentTimeMillis()
    if (now - lastResetTime > 1000) {
      messageCount = 0
      lastResetTime = now
    }
    messageCount += 1
    messageCount <= RateLimitPerSecond
  }

  private def handleIncomingData(data: ByteString): Unit = {
    val bytes = data.toArray

    if (bytes.length > MaxMessageSize) {
      log.warning(s"Received oversized message: ${bytes.length} bytes")
      return
    }

    SecureSerializer.deserialize(bytes, MaxMessageSize) match {
      case Right(message) =>
        log.debug(s"Successfully deserialized: ${message.getClass.getSimpleName}")
        processor ! message

      case Left(error) =>
        log.warning(s"Failed to deserialize message: $error")
    }
  }
}

// TCP server actor
class TcpServer(processor: ActorRef, bindAddress: String, port: Int) extends Actor with ActorLogging {

  import Tcp._
  import context.system

  IO(Tcp) ! Bind(self, new InetSocketAddress(bindAddress, port))

  override def receive: Receive = {
    case Bound(localAddress) =>
      log.info(s"Server bound to $localAddress")

    case CommandFailed(_: Bind) =>
      log.error("Failed to bind")
      context.stop(self)

    case Connected(remote, _) =>
      log.info(s"New connection from $remote")
      val handler = context.actorOf(Props(new ConnectionHandler(processor)))
      sender() ! Register(handler)
  }
}

